const summary = $input.first().json.text; // LLM Chain output
const recentMessages = $('Split messages').first().json.recentMessages;
const sessionId = $('Split messages').first().json.sessionId;

// store summary as an AI message so n8n's memory loader recognizes it
const summaryRecord = {
  type: 'ai',
  data: {
    content: `📋 [Conversation Summary — context from earlier in this session]:\n${summary}`,
    tool_calls: [],
    invalid_tool_calls: [],
    additional_kwargs: {},
    response_metadata: {}
  }
};

const newMessages = [summaryRecord, ...recentMessages];

return [{
  json: {
    sessionId,
    messages: newMessages
  }
}];

const messages = $input.first().json.messages || [];

// keep last 6 messages (roughly 2 recent interactions including any tool messages)
const recentMessages = messages.slice(-6);
const oldMessages = messages.slice(0, -6);

// build clean text for summarization — skip tool messages and raw tool call lines
const summaryInput = oldMessages
  .filter(m => m.type === 'human' || m.type === 'ai')
  .filter(m => !m.data.content.startsWith('Calling '))
  .map(m => {
    const role = m.type === 'human' ? 'Customer' : 'Vista';
    return `${role}: ${m.data.content}`;
  })
  .join('\n\n');

return [{
  json: {
    summaryInput,
    recentMessages,
    sessionId: $input.first().json.sessionId
  }
}];

const messages = $input.first().json.messages || [];

// count only human + ai pairs (ignore tool messages)
const turns = messages.filter(m => m.type === 'human' || m.type === 'ai');
const interactionCount = Math.floor(turns.length / 2);

return [{
  json: {
    shouldSummarize: interactionCount >= 5,
    interactionCount,
    sessionId: $input.first().json.sessionId,
    messages
  }
}];

const raw = $input.first().json.output || $input.first().json.text || '';

// strip markdown code fences if the model wraps it
const cleaned = raw.replace(/```json|```/g, '').trim();

let scores;
try {
  scores = JSON.parse(cleaned);
} catch(e) {
  scores = {
    relevance: null,
    correctness: null,
    tone: null,
    completeness: null,
    overall: null,
    reasoning: "Parse error: " + raw.slice(0, 100),
    flagged: true
  };
}

return [{
  json: {
    sessionId: $('Orchestrator').first().json.sessionId,
    channel: $('Orchestrator').first().json.channel,
    user_message: $('Orchestrator').first().json.userMessage,
    agent_response: $('Orchestrator').first().json.output,
    scores,
    timestamp: new Date().toISOString()
  }
}];
